// Builder-safe helper: resolve the effective parser spec + adapter from the version registry.
//
// Goal: Dispatch is version-driven (parser_version -> registry spec -> spec.adapter).
// Source adapter hints are advisory only. Drift should be visible via warnings.

import {
  normalizeParserVersionKeyStrict,
  resolveParserVersionSpec,
  normalizeAdapterHintForMatch,
} from "../versions";

export function resolveParserSpec({ state, parser_version, sourceRow }) {
  const raw = String(parser_version || "").trim();

  if (!raw) {
    return {
      ok: false,
      implemented: false,
      status: 400,
      code: "PARSER_VERSION_REQUIRED",
      message: "parser_version is required (select a version in Panel C).",
    };
  }

  const normalizedParserVersion = normalizeParserVersionKeyStrict(raw);
  if (!normalizedParserVersion) {
    return {
      ok: false,
      implemented: false,
      status: 409,
      code: "INVALID_PARSER_VERSION",
      message:
        "parser_version must be a real registry key (for example: html_single_index_v1, html_multi_index_v1, html_json_index_v1, pdf_v1, hybrid_v1).",
      parser_version: raw,
    };
  }

  const spec = resolveParserVersionSpec({
    version_key: normalizedParserVersion,
    state,
    source_class: sourceRow?.source_class || null,
  });

  if (!spec?.ok) {
    return {
      ok: false,
      implemented: false,
      status: 409,
      code: spec?.error || "PARSER_VERSION_NOT_ALLOWED",
      message: "parser_version is not allowed for this state/source_class.",
      parser_version: normalizedParserVersion,
      supported_source_classes: spec?.supported_source_classes || [],
      states: spec?.states || ["*"],
    };
  }

  if (spec.implemented !== true) {
    return {
      ok: false,
      implemented: false,
      status: 409,
      code: "PARSER_VERSION_NOT_IMPLEMENTED",
      message: "Selected parser_version is not implemented.",
      parser_version: normalizedParserVersion,
      adapter_expected: spec?.adapter || null,
    };
  }

  const warnings = [];

  const hintedRaw = String(sourceRow?.adapter_hint || "").trim();
  const hinted = hintedRaw ? normalizeAdapterHintForMatch(hintedRaw) : "";
  const expected = String(spec?.adapter || "").trim();

  if (hinted && expected && hinted !== expected) {
    warnings.push({
      code: "SOURCE_ADAPTER_HINT_MISMATCH",
      message: `Source adapter_hint (${hintedRaw}) differs from selected version adapter (${expected}). Ignoring hint.`,
      adapter_hint: hintedRaw,
      adapter_hint_normalized: hinted,
      adapter_selected: expected,
    });
  }

  return {
    ok: true,
    spec,
    adapterKey: expected,
    normalizedParserVersion,
    warnings,
  };
}

